import{_ as a,o as t,c as s,a0 as i}from"./chunks/framework.Cl79jK2u.js";const g=JSON.parse('{"title":"Telegram","description":"","frontmatter":{},"headers":[],"relativePath":"guide/telegram.md","filePath":"guide/telegram.md"}'),n={name:"guide/telegram.md"};function o(r,e,l,h,d,p){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="telegram" tabindex="-1">Telegram <a class="header-anchor" href="#telegram" aria-label="Permalink to &quot;Telegram&quot;">​</a></h1><p>Moxie connects to Telegram using the Bot API with long polling. No webhooks, no public URLs needed.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><h3 id="_1-create-a-bot" tabindex="-1">1. Create a bot <a class="header-anchor" href="#_1-create-a-bot" aria-label="Permalink to &quot;1. Create a bot&quot;">​</a></h3><p>Open <a href="https://t.me/BotFather" target="_blank" rel="noreferrer">BotFather</a> in Telegram and send <code>/newbot</code>. Choose a display name and a username ending in <code>bot</code>. BotFather returns a token like <code>123456789:AAH...</code>.</p><h3 id="_2-get-your-chat-id" tabindex="-1">2. Get your chat ID <a class="header-anchor" href="#_2-get-your-chat-id" aria-label="Permalink to &quot;2. Get your chat ID&quot;">​</a></h3><p>Send any message to your new bot, then visit:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.telegram.org/bot&lt;TOKEN&gt;/getUpdates</span></span></code></pre></div><p>In the JSON response, find your chat ID at <code>result[0].message.chat.id</code>. It&#39;s a numeric value like <code>412407481</code>.</p><h3 id="_3-configure" tabindex="-1">3. Configure <a class="header-anchor" href="#_3-configure" aria-label="Permalink to &quot;3. Configure&quot;">​</a></h3><p>Add to <code>~/.config/moxie/config.json</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;channels&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;telegram&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;provider&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;telegram&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123456789:AAH...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;channel_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;412407481&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Or use <code>moxie init</code> for interactive setup.</p><h2 id="configuration-reference" tabindex="-1">Configuration reference <a class="header-anchor" href="#configuration-reference" aria-label="Permalink to &quot;Configuration reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>provider</code></td><td>Yes</td><td>Must be <code>&quot;telegram&quot;</code></td></tr><tr><td><code>token</code></td><td>Yes</td><td>Bot token from BotFather</td></tr><tr><td><code>channel_id</code></td><td>Yes</td><td>Numeric chat ID for your conversation</td></tr></tbody></table><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><h3 id="message-formatting" tabindex="-1">Message formatting <a class="header-anchor" href="#message-formatting" aria-label="Permalink to &quot;Message formatting&quot;">​</a></h3><p>Moxie instructs the agent to format responses in Telegram HTML:</p><ul><li><code>&lt;b&gt;bold&lt;/b&gt;</code>, <code>&lt;i&gt;italic&lt;/i&gt;</code>, <code>&lt;code&gt;inline&lt;/code&gt;</code></li><li><code>&lt;pre&gt;code blocks&lt;/pre&gt;</code></li><li><code>&lt;a href=&quot;url&quot;&gt;links&lt;/a&gt;</code></li></ul><p>If HTML parsing fails (e.g. malformed tags from the agent), the message is automatically resent as plain text.</p><h3 id="long-messages" tabindex="-1">Long messages <a class="header-anchor" href="#long-messages" aria-label="Permalink to &quot;Long messages&quot;">​</a></h3><p>Responses longer than 4000 characters are split into multiple messages at paragraph boundaries, then line boundaries, then word boundaries.</p><h3 id="file-attachments" tabindex="-1">File attachments <a class="header-anchor" href="#file-attachments" aria-label="Permalink to &quot;File attachments&quot;">​</a></h3><p>The agent can send files back by including <code>&lt;send&gt;/path/to/file&lt;/send&gt;</code> in its response. Images (<code>.jpg</code>, <code>.png</code>, <code>.gif</code>, <code>.webp</code>) are sent as photos; other files as documents.</p><h3 id="inbound-photos" tabindex="-1">Inbound photos <a class="header-anchor" href="#inbound-photos" aria-label="Permalink to &quot;Inbound photos&quot;">​</a></h3><p>Photos sent to the bot are downloaded and passed to the agent as file paths. The agent can read the file to analyze the image.</p><h3 id="typing-indicator" tabindex="-1">Typing indicator <a class="header-anchor" href="#typing-indicator" aria-label="Permalink to &quot;Typing indicator&quot;">​</a></h3><p>While the agent is working, Moxie sends a continuous typing indicator. Activity updates (tool calls, file operations) appear as status messages that are cleaned up when the response arrives.</p><h2 id="running-only-telegram" tabindex="-1">Running only Telegram <a class="header-anchor" href="#running-only-telegram" aria-label="Permalink to &quot;Running only Telegram&quot;">​</a></h2><p>If you have multiple transports configured but want to run only Telegram:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --transport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div>`,31)])])}const u=a(n,[["render",o]]);export{g as __pageData,u as default};
